$(document).ready(function(){if(0==$(".scrollspy_new").length){let l=document.querySelectorAll(".blog-right-scrollspy div"),t=document.querySelectorAll(".blog-left-scrollspy-ol a");window.onscroll=()=>{l.forEach(l=>{let e=window.scrollY,o=l.offsetTop-60,s=l.offsetHeight,c=l.getAttribute("id");e>=o&&e<o+s&&t.forEach(l=>{l.classList.remove("active"),document.querySelector(".blog-left-scrollspy-ol a[href*="+c+"]").classList.add("active")})})},$(".artical_content_metafeild").css("display","flex")}else{const initScrollspy=()=>{if(1==$(".blog-left-scrollspy-ol > a").length){var l=1,t=$(".scrollspy_new .article-template__content h2").length;1!=t?$(".scrollspy_new .article-template__content h2:not(.article_meta_title)").each(function(){if(t<l)return!1;$(this).attr("id","scrollspy_"+l).attr("class","article_meta_title"),$(".blog-left-scrollspy-ol").append('<a href="#scrollspy_'+l+'" class="">'+$(this).text()+"</a>"),l++}):$(".artical_content_metafeild").addClass("notitle"),$(".artical_content_metafeild").css("display","flex")}else $(".artical_content_metafeild").css("display","flex")};initScrollspy();let l=$(".blog-right-scrollspy .article-template__content h2");$(window).on("scroll",function(){0!=l.length&&l.each(function(){let l=$(window).scrollTop(),t=$(this).offset().top-60,e=$(this).outerHeight(),o=$(this).attr("id");l>=t&&l<t+e&&($(".blog-left-scrollspy-ol a").removeClass("active"),$(`.blog-left-scrollspy-ol a[href*="${o}"]`).addClass("active"))})})}});